/**
 * @summary Get hourly/daily consumption data for chart
 */
export const getGetConsumptionChartUrl = (
  params?: GetConsumptionChartParams,
) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/dashboard/consumption-chart?${stringifiedParams}`
    : `/api/dashboard/consumption-chart`;
};

export const getConsumptionChart = async (
  params?: GetConsumptionChartParams,
  options?: RequestInit,
): Promise<ConsumptionDataPoint[]> => {
  return customFetch<ConsumptionDataPoint[]>(
    getGetConsumptionChartUrl(params),
    {
      ...options,
      method: "GET",
    },
  );
};

export const getGetConsumptionChartQueryKey = (
  params?: GetConsumptionChartParams,
) => {
  return [
    `/api/dashboard/consumption-chart`,
    ...(params ? [params] : []),
  ] as const;
};

export const getGetConsumptionChartQueryOptions = <
  TData = Awaited<ReturnType<typeof getConsumptionChart>>,
  TError = ErrorType<unknown>,
>(
  params?: GetConsumptionChartParams,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof getConsumptionChart>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
) => {
  const { query: queryOptions, request: requestOptions } = options ?? {};

  const queryKey =
    queryOptions?.queryKey ?? getGetConsumptionChartQueryKey(params);

  const queryFn: QueryFunction<
    Awaited<ReturnType<typeof getConsumptionChart>>
  > = ({ signal }) =>
    getConsumptionChart(params, { signal, ...requestOptions });

  return { queryKey, queryFn, ...queryOptions } as UseQueryOptions<
    Awaited<ReturnType<typeof getConsumptionChart>>,
    TError,
    TData
  > & { queryKey: QueryKey };
};

export type GetConsumptionChartQueryResult = NonNullable<
  Awaited<ReturnType<typeof getConsumptionChart>>
>;
export type GetConsumptionChartQueryError = ErrorType<unknown>;

